class Solution {
    public int appendCharacters(String s, String t) {
        int result = 0;
        int tLength = t.length();
        int sLength = s.length();

        for (int i = 0; i < sLength; i++) {
            if (t.charAt(tLength - 1) == s.charAt(i)) {
                result++;
                tLength--;
            }
        }

        return result;
    }
}
